import { createSlice, PayloadAction } from '@reduxjs/toolkit';

export type ZoomLevel = 'strategic' | 'tactical' | 'operational';

interface CanvasState {
  zoom: number;
  zoomLevel: ZoomLevel;
  pan: { x: number; y: number };
  viewport: { width: number; height: number };
}

const initialState: CanvasState = {
  zoom: 1,
  zoomLevel: 'operational',
  pan: { x: 0, y: 0 },
  viewport: { width: 0, height: 0 },
};

const canvasSlice = createSlice({
  name: 'canvas',
  initialState,
  reducers: {
    setZoom: (state, action: PayloadAction<number>) => {
      state.zoom = action.payload;
      // Determine zoom level based on zoom value
      if (action.payload <= 0.15) {
        state.zoomLevel = 'strategic';
      } else if (action.payload <= 0.6) {
        state.zoomLevel = 'tactical';
      } else {
        state.zoomLevel = 'operational';
      }
    },
    setPan: (state, action: PayloadAction<{ x: number; y: number }>) => {
      state.pan = action.payload;
    },
    setViewport: (state, action: PayloadAction<{ width: number; height: number }>) => {
      state.viewport = action.payload;
    },
  },
});

export const { setZoom, setPan, setViewport } = canvasSlice.actions;
export default canvasSlice.reducer;
</parameter>
