import { createSlice, PayloadAction } from '@reduxjs/toolkit';

export type FleetType = 'kinki' | 'alstom';
export type TrainStatus = 'available' | 'in-maintenance' | 'scheduled';

export interface Train {
  id: string;
  fleetType: FleetType;
  trainNumber: string;
  status: TrainStatus;
  lastMaintenance: string | null;
  nextMaintenance: string | null;
}

interface FleetState {
  trains: Train[];
  selectedTrainId: string | null;
  loading: boolean;
  error: string | null;
}

const initialState: FleetState = {
  trains: [],
  selectedTrainId: null,
  loading: false,
  error: null,
};

const fleetSlice = createSlice({
  name: 'fleet',
  initialState,
  reducers: {
    setTrains: (state, action: PayloadAction<Train[]>) => {
      state.trains = action.payload;
    },
    selectTrain: (state, action: PayloadAction<string | null>) => {
      state.selectedTrainId = action.payload;
    },
    updateTrainStatus: (
      state,
      action: PayloadAction<{ id: string; status: TrainStatus }>
    ) => {
      const train = state.trains.find((t) => t.id === action.payload.id);
      if (train) {
        train.status = action.payload.status;
      }
    },
    setLoading: (state, action: PayloadAction<boolean>) => {
      state.loading = action.payload;
    },
    setError: (state, action: PayloadAction<string | null>) => {
      state.error = action.payload;
    },
  },
});

export const { setTrains, selectTrain, updateTrainStatus, setLoading, setError } =
  fleetSlice.actions;
export default fleetSlice.reducer;
</parameter>
