import { createSlice, PayloadAction } from '@reduxjs/toolkit';

export type MaintenanceType = 'A1' | 'A2' | 'B' | 'C' | 'D';

export interface MaintenanceEvent {
  id: string;
  trainId: string;
  type: MaintenanceType;
  startDate: string;
  endDate: string;
  trackId: string;
  status: 'planned' | 'in-progress' | 'completed';
}

interface ScheduleState {
  events: MaintenanceEvent[];
  selectedEventId: string | null;
  dateRange: { start: string; end: string };
}

const initialState: ScheduleState = {
  events: [],
  selectedEventId: null,
  dateRange: {
    start: new Date().toISOString(),
    end: new Date(Date.now() + 365 * 24 * 60 * 60 * 1000).toISOString(),
  },
};

const scheduleSlice = createSlice({
  name: 'schedule',
  initialState,
  reducers: {
    setEvents: (state, action: PayloadAction<MaintenanceEvent[]>) => {
      state.events = action.payload;
    },
    addEvent: (state, action: PayloadAction<MaintenanceEvent>) => {
      state.events.push(action.payload);
    },
    updateEvent: (state, action: PayloadAction<MaintenanceEvent>) => {
      const index = state.events.findIndex((e) => e.id === action.payload.id);
      if (index !== -1) {
        state.events[index] = action.payload;
      }
    },
    removeEvent: (state, action: PayloadAction<string>) => {
      state.events = state.events.filter((e) => e.id !== action.payload);
    },
    selectEvent: (state, action: PayloadAction<string | null>) => {
      state.selectedEventId = action.payload;
    },
    setDateRange: (state, action: PayloadAction<{ start: string; end: string }>) => {
      state.dateRange = action.payload;
    },
  },
});

export const { setEvents, addEvent, updateEvent, removeEvent, selectEvent, setDateRange } =
  scheduleSlice.actions;
export default scheduleSlice.reducer;
