import { createSlice, PayloadAction } from '@reduxjs/toolkit';
import type { MaintenanceEvent } from './scheduleSlice';

interface SimulationState {
  isActive: boolean;
  baselineEvents: MaintenanceEvent[];
  simulatedEvents: MaintenanceEvent[];
  costDelta: number;
}

const initialState: SimulationState = {
  isActive: false,
  baselineEvents: [],
  simulatedEvents: [],
  costDelta: 0,
};

const simulationSlice = createSlice({
  name: 'simulation',
  initialState,
  reducers: {
    startSimulation: (state, action: PayloadAction<MaintenanceEvent[]>) => {
      state.isActive = true;
      state.baselineEvents = action.payload;
      state.simulatedEvents = [...action.payload];
      state.costDelta = 0;
    },
    updateSimulatedEvent: (state, action: PayloadAction<MaintenanceEvent>) => {
      const index = state.simulatedEvents.findIndex((e) => e.id === action.payload.id);
      if (index !== -1) {
        state.simulatedEvents[index] = action.payload;
      }
    },
    setCostDelta: (state, action: PayloadAction<number>) => {
      state.costDelta = action.payload;
    },
    commitSimulation: (state) => {
      state.isActive = false;
      state.baselineEvents = [];
      state.simulatedEvents = [];
      state.costDelta = 0;
    },
    cancelSimulation: (state) => {
      state.isActive = false;
      state.simulatedEvents = [];
      state.costDelta = 0;
    },
  },
});

export const {
  startSimulation,
  updateSimulatedEvent,
  setCostDelta,
  commitSimulation,
  cancelSimulation,
} = simulationSlice.actions;
export default simulationSlice.reducer;
